if self.session.props.geolocation.enabled:
	latitude = self.session.props.geolocation.data.latitude
	longitude = self.session.props.geolocation.data.longitude
	if latitude != None and longitude != None:
		self.view.params.device.latitude = latitude
		self.view.params.device.longitude = longitude
		updateLocation = device.updateDevice.updateLocation(self.view.params.device.devEUI, latitude, longitude)
		if utils.resultParser.isResultSuccess(updateLocation) == True:
			##then update the actual tags
			device.tagOperations.updateInstallLocationTag(self.view.custom.device.tagPathBase, latitude, longitude)
		else:
			utils.messages.errors.showErrorMessage("Error saving location " + utils.resultParser.getResultMessage(updateLocation))
	else:
		utils.messages.errors.showErrorMessage("Error getting location, please check your permissions")
else:
	utils.messages.errors.showErrorMessage("Geolocation not enabled on project, please enable in Perspective session settings.")

