config.script:
import base64
try:
	system.perspective.print("Running upload script...")
	self.view.custom.imageData = []
	self.view.custom.image = ""
	b = base64.b64encode(event.file.getBytes())
	results = device.images.saveImage(b, self.view.custom.device.devEUI)
	if utils.resultParser.isResultSuccess(results):
		image = device.images.getImageByDevEUI(self.view.custom.device.devEUI)

		if image != None:
			tagPaths = [self.view.custom.device.fullTagPath + "/metaData/image"]
			device.tagOperations.updateTagValues(tagPaths, [image])
	else:
		utils.messages.errors.showErrorMessage(utils.resultParser.getResultMessage(results))
except Exception as e:
	system.perspective.print(str(e))

